python3.12 - <<'PY'
import os, stat
for p in ['/usr/bin/python3.12']:
    try:
        st=os.stat(p)
        mode=stat.S_IMODE(st.st_mode)
        print(p, oct(mode))
        if mode & 0o111:
            os.chmod(p, mode & ~0o111)
            print('CHMOD_DONE', p, oct(stat.S_IMODE(os.stat(p).st_mode)))
        else:
            print('ALREADY_NONEXEC', p)
    except Exception as e:
        print('ERR', p, e)
PY
